import * as React from 'react';
import Box from '@mui/joy/Box';
import Sheet from '@mui/joy/Sheet';
import Button from '@mui/joy/Button';
import FormControl from '@mui/joy/FormControl';
import FormLabel from '@mui/joy/FormLabel';
import Input from '@mui/joy/Input';
import Typography from '@mui/joy/Typography';
import BadgeRoundedIcon from '@mui/icons-material/BadgeRounded';
import LogoutRoundedIcon from '@mui/icons-material/LogoutRounded';
import { useAuth } from '../AuthContext';

export default function Login() {
    const { isLoggedIn, login, logout } = useAuth();
    const [username, setUsername] = React.useState('');
    const [password, setPassword] = React.useState('');
    const [error, setError] = React.useState('');
    const [loading, setLoading] = React.useState(false);

    const handleLogin = async () => {
        if (!username || !password) return;
        setLoading(true);
        setError('');
        const success = await login(username, password);
        setLoading(false);
        if (!success) {
            setError('Login failed. Check your credentials.');
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter') {
            handleLogin();
        }
    };

    if (isLoggedIn) {
        return (
            <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
                <Sheet variant="outlined" sx={{ width: 340, p: 4, borderRadius: 'sm', display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 2 }}>
                    <BadgeRoundedIcon sx={{ fontSize: 48 }} />
                    <Typography level="h4">Authenticated</Typography>
                    <Typography level="body-sm" sx={{ textAlign: 'center' }}>
                        You are currently logged in to the Orgs server.
                    </Typography>
                    <Button
                        color="danger"
                        variant="soft"
                        startDecorator={<LogoutRoundedIcon />}
                        onClick={logout}
                        fullWidth
                    >
                        Log Out
                    </Button>
                </Sheet>
            </Box>
        );
    }

    return (
        <Box sx={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
            <Sheet variant="outlined" sx={{ width: 340, p: 4, borderRadius: 'sm' }}>
                <Typography level="h4" sx={{ mb: 2, textAlign: 'center' }}>
                    Orgs Login
                </Typography>
                <FormControl sx={{ mb: 2 }}>
                    <FormLabel>Username</FormLabel>
                    <Input
                        value={username}
                        onChange={(e) => setUsername(e.target.value)}
                        onKeyDown={(e) => { if (e.key === 'Enter') document.getElementById('login-password')?.focus(); }}
                        autoFocus
                    />
                </FormControl>
                <FormControl sx={{ mb: 2 }}>
                    <FormLabel>Password</FormLabel>
                    <Input
                        id="login-password"
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        onKeyDown={handleKeyDown}
                    />
                </FormControl>
                {error && (
                    <Typography color="danger" level="body-sm" sx={{ mb: 1 }}>
                        {error}
                    </Typography>
                )}
                <Button
                    fullWidth
                    loading={loading}
                    onClick={handleLogin}
                >
                    Log In
                </Button>
            </Sheet>
        </Box>
    );
}
