import * as React from 'react';
import { Auth } from './auth';

interface AuthContextType {
    isLoggedIn: boolean;
    login: (username: string, password: string) => Promise<boolean>;
    logout: () => void;
}

const AuthContext = React.createContext<AuthContextType>({
    isLoggedIn: false,
    login: async () => false,
    logout: () => {},
});

export function AuthProvider({ children }: { children: React.ReactNode }) {
    const [loggedIn, setLoggedIn] = React.useState(() => {
        Auth.get().init();
        return Auth.get().isLoggedIn();
    });

    React.useEffect(() => {
        const unsub = Auth.get().subscribe(setLoggedIn);
        return unsub;
    }, []);

    const login = React.useCallback(
        (username: string, password: string) => Auth.get().login(username, password),
        []
    );

    const logout = React.useCallback(() => Auth.get().logout(), []);

    const value = React.useMemo(
        () => ({ isLoggedIn: loggedIn, login, logout }),
        [loggedIn, login, logout]
    );

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    return React.useContext(AuthContext);
}
