import * as React from 'react';
import Container from '@mui/material/Container';
import Typography from '@mui/material/Typography';
import Box from '@mui/material/Box';
import Link from '@mui/material/Link';
import ProTip from './ProTip';
import { CssVarsProvider } from '@mui/joy/styles';
import CssBaseline from '@mui/joy/CssBaseline';
import Button from '@mui/joy/Button';
import Breadcrumbs from '@mui/joy/Breadcrumbs';
// icons
import HomeRoundedIcon from '@mui/icons-material/HomeRounded';
import ChevronRightRoundedIcon from '@mui/icons-material/ChevronRightRounded';
import DownloadRoundedIcon from '@mui/icons-material/DownloadRounded';

import useScript from './useScript';
import FunctionBar from './components/FunctionBar';
import AppBar from './components/AppBar';
import Search from './components/Search';
import Agenda from './components/Agenda';
import Login from './components/Login';
import OrderList from './components/OrderList';
import Header from './components/Header';
import ColorSchemeToggle from './components/ColorSchemeToggle';
import { AuthProvider, useAuth } from './AuthContext';

const useEnhancedEffect =
  typeof window !== 'undefined' ? React.useLayoutEffect : React.useEffect;


function Temp() {
  return (<div><Typography>TEST INFO</Typography></div>);
}

function Copyright() {
  return (
    <Typography variant="body2" color="text.secondary" align="center">
      {'Copyright © '}
      <Link color="inherit" href="https://algoriststudios.com/">
        Algorist
      </Link>{' '}
      {new Date().getFullYear()}.
    </Typography>
  );
}



function AppContent() {
  const { isLoggedIn } = useAuth();
  const [activeApp, setActiveApp] = React.useState("Search");

  var application = undefined;
  if (!isLoggedIn) {
    application = <Login />;
  } else if (activeApp === "Authentication") {
    application = <Login />;
  } else if (activeApp === "Agenda") {
    application = <Agenda />;
  } else if (activeApp === "Search") {
    application = <Search />;
  }

  const displayApp = !isLoggedIn ? "Authentication" : activeApp;

  return (
    <Box sx={{ display: 'flex', minHeight: '100dvh' }}>
      <Header />
      <FunctionBar />
      <AppBar onActiveApp={setActiveApp} />
      <Box
        component="main"
        className="MainContent"
        sx={{
          px: {
            xs: 2,
            md: 6,
          },
          pt: {
            xs: 'calc(12px + var(--Header-height))',
            sm: 'calc(12px + var(--Header-height))',
            md: 3,
          },
          pb: {
            xs: 2,
            sm: 2,
            md: 3,
          },
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          minWidth: 0,
          height: '100dvh',
          gap: 1,
        }}
      >
        <Box sx={{ display: 'flex', alignItems: 'center' }}>
          <Breadcrumbs
            size="sm"
            aria-label="breadcrumbs"
            separator={<ChevronRightRoundedIcon fontSize="small" />}
          >
            <Link
              underline="none"
              color="neutral"
              href="#some-link"
              aria-label="Home"
            >
              <HomeRoundedIcon />
            </Link>
            <Link
              underline="hover"
              color="neutral"
              href="#some-link"
              fontSize={12}
              fontWeight={500}
            >
              Application
            </Link>
            <Typography color="primary" fontWeight={500} fontSize={12}>
              {displayApp}
            </Typography>
          </Breadcrumbs>
          <ColorSchemeToggle
            sx={{ ml: 'auto', display: { xs: 'none', md: 'inline-flex' } }}
          />
        </Box>
        <Box
            sx={{
              display: 'flex',
              my: 1,
              gap: 1,
              flexDirection: { xs: 'column', sm: 'row' },
              alignItems: { xs: 'start', sm: 'center' },
              flexWrap: 'wrap',
              justifyContent: 'space-between',
            }}
          >
            <Typography variant="h2">{displayApp}</Typography>
            <Button
              color="primary"
              startDecorator={<DownloadRoundedIcon />}
              size="sm"
            >
              Download PDF
            </Button>
          </Box>
          {application}
        </Box>
      </Box>
  );
}

export default function App() {
  return (
    <CssVarsProvider disableTransitionOnChange>
      <CssBaseline />
      <AuthProvider>
        <AppContent />
      </AuthProvider>
    </CssVarsProvider>
  );
}
