import * as React from 'react';
import AspectRatio, { AspectRatioProps } from '@mui/joy/AspectRatio';
import Link from '@mui/material/Link';

export default function MyLogo({ sx, ...props }: AspectRatioProps) {
  return (
    <AspectRatio
      ratio="1"
      variant="plain"
      {...props}
      sx={[
        {
          width: 36,
        },
        ...(Array.isArray(sx) ? sx : [sx]),
      ]}
    >
      <div>

        <Link rel="orgmode" href="https://orgmode.org">
          <img src="https://orgmode.org/resources/img/org-mode-unicorn.svg" width="36"/>
        </Link>
      </div>
    </AspectRatio>
  );
}
