    public static async doGet<T>(url: any, signal: AbortSignal | null = null, retry: boolean = false): Promise<T> {
        const headers: Headers = new Headers();
        headers.set('Content-Type', 'application/json');
        headers.set('Accept', 'application/json');
        const token = Auth.get().getToken();
        if (token) {
            headers.set('Authorization', 'Bearer ' + token);
        }

        if(url instanceof String) {
            url = new URL(Sets.orgsConnection + url);
        }

        const request: RequestInfo = new Request(url, {
            method: 'GET',
            headers: headers,
        });
        try{
            var res = null;
            if (signal) {
                res = await fetch(request, {signal});
            } else {
                res = await fetch(request);
            }
            if (res.status === 401 && !retry) {
                Auth.get().logout();
                await Auth.get().awaitLogin();
                return await this.doGet<T>(url, signal, true);
            }
            return res.json() as T;
        } catch(error: any) {
            console.error(error.message);
        }
        return [] as T;
    }

    public static async doDelete<T>(url: any, payload: any, retry: boolean = false): Promise<T> {
        const headers: Headers = new Headers();
        headers.set('Content-Type', 'application/json');
        headers.set('Accept', 'application/json');
        const token = Auth.get().getToken();
        if (token) {
            headers.set('Authorization', 'Bearer ' + token);
        }

        if(url instanceof String) {
            url = new URL(Sets.orgsConnection + url);
        }

        const request: RequestInfo = new Request(url, {
            method: 'DELETE',
            headers: headers,
            body: JSON.stringify(payload),
        });

        try{
            var res = await window.fetch(request);
            if (res.status === 401 && !retry) {
                Auth.get().logout();
                await Auth.get().awaitLogin();
                return await this.doDelete<T>(url, payload, true);
            }
            return res.json() as T;
        } catch(error: any) {
            console.error(error.message);
        }
        return [] as T;
    }

