    public static async agendaRest<T>(date: Date = new Date()): Promise<T> {
        var url: URL = new URL(Sets.orgsConnection + "/search");

        url.searchParams.append('query',`!IsProject() && !IsArchived() && IsTodo() && OnDate("${date.getFullYear()} ${pad2(date.getDate())} ${pad2(date.getMonth()+1)}")`);
        return await this.doGet(url);
    }

