import { Sets } from './config';

interface AuthToken {
    token: string;
    expiresAt: number; // unix timestamp ms
}

type AuthStateListener = (loggedIn: boolean) => void;

const COOKIE_NAME = 'orgs_auth';

export class Auth {
    private static instance: Auth;
    private currentToken: AuthToken | null = null;
    private refreshTimer: ReturnType<typeof setTimeout> | null = null;
    private listeners: Set<AuthStateListener> = new Set();

    private constructor() {}

    public static get(): Auth {
        if (!Auth.instance) {
            Auth.instance = new Auth();
        }
        return Auth.instance;
    }

    public init() {
        if (this.currentToken) {
            return; // already initialized
        }
        const stored = this.loadTokenFromCookie();
        if (stored && stored.token && stored.expiresAt && Date.now() < stored.expiresAt) {
            this.currentToken = stored;
            this.scheduleRefresh();
        }
    }

    public isLoggedIn(): boolean {
        return this.currentToken !== null && !this.isExpired();
    }

    public isExpired(): boolean {
        if (!this.currentToken) {
            return true;
        }
        return Date.now() >= this.currentToken.expiresAt;
    }

    public getToken(): string | null {
        if (!this.currentToken || this.isExpired()) {
            return null;
        }
        return this.currentToken.token;
    }

    public subscribe(listener: AuthStateListener): () => void {
        this.listeners.add(listener);
        return () => {
            this.listeners.delete(listener);
        };
    }

    public async login(username: string, password: string): Promise<boolean> {
        try {
            const url = Sets.orgsConnection + '/login';
            const res = await fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json',
                },
                body: JSON.stringify({ username, password }),
            });
            if (!res.ok) {
                return false;
            }
            const data = await res.json();
            if (data.token && data.ExpiresAt) {
                const expiresAt = new Date(data.ExpiresAt).getTime();
                this.currentToken = { token: data.token, expiresAt };
                this.saveTokenToCookie(this.currentToken);
                this.scheduleRefresh();
                this.notifyListeners();
                return true;
            }
            return false;
        } catch (e: any) {
            console.error('Login request failed:', e.message);
            return false;
        }
    }

    public logout() {
        this.cancelRefresh();
        this.currentToken = null;
        this.clearCookie();
        this.notifyListeners();
    }

    public awaitLogin(): Promise<boolean> {
        if (this.isLoggedIn()) {
            return Promise.resolve(true);
        }
        return new Promise((resolve) => {
            const unsub = this.subscribe((loggedIn) => {
                if (loggedIn) {
                    unsub();
                    resolve(true);
                }
            });
        });
    }

    private notifyListeners() {
        const loggedIn = this.isLoggedIn();
        this.listeners.forEach((listener) => listener(loggedIn));
    }

    private cancelRefresh() {
        if (this.refreshTimer) {
            clearTimeout(this.refreshTimer);
            this.refreshTimer = null;
        }
    }

    private scheduleRefresh() {
        this.cancelRefresh();
        if (!this.currentToken) {
            return;
        }
        const remaining = this.currentToken.expiresAt - Date.now();
        const delay = Math.max(remaining * 0.75, 10_000);
        this.refreshTimer = setTimeout(() => this.refreshToken(), delay);
    }

    private async refreshToken() {
        this.refreshTimer = null;
        if (!this.currentToken || this.isExpired()) {
            return;
        }
        try {
            const url = Sets.orgsConnection + '/refresh';
            const res = await fetch(url, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    'Accept': 'application/json',
                    'Authorization': 'Bearer ' + this.currentToken.token,
                },
                body: JSON.stringify({}),
            });
            if (!res.ok) {
                console.log('Token refresh failed with status ' + res.status);
                return;
            }
            const data = await res.json();
            if (data.token && data.ExpiresAt) {
                const expiresAt = new Date(data.ExpiresAt).getTime();
                this.currentToken = { token: data.token, expiresAt };
                this.saveTokenToCookie(this.currentToken);
                this.scheduleRefresh();
            }
        } catch (e: any) {
            console.log('Token refresh error:', e.message);
        }
    }

    private saveTokenToCookie(token: AuthToken) {
        const value = JSON.stringify({ token: token.token, expiresAt: token.expiresAt });
        const expires = new Date(token.expiresAt).toUTCString();
        document.cookie = `${COOKIE_NAME}=${encodeURIComponent(value)}; expires=${expires}; path=/; SameSite=Strict`;
    }

    private loadTokenFromCookie(): AuthToken | null {
        const cookies = document.cookie.split(';');
        for (const cookie of cookies) {
            const [name, ...rest] = cookie.trim().split('=');
            if (name === COOKIE_NAME) {
                try {
                    const value = decodeURIComponent(rest.join('='));
                    const parsed = JSON.parse(value);
                    if (parsed.token && parsed.expiresAt) {
                        return { token: parsed.token, expiresAt: parsed.expiresAt };
                    }
                } catch {
                    return null;
                }
            }
        }
        return null;
    }

    private clearCookie() {
        document.cookie = `${COOKIE_NAME}=; expires=Thu, 01 Jan 1970 00:00:00 GMT; path=/; SameSite=Strict`;
    }
}
