// ── Types ──

interface AgendaEvent {
  Headline: string;
  Status: string;
  Hash: string;
  Date: {
    Start: string;
    End: string;
  };
  Filename: string;
  LineNum: number;
  Tags: string[] | null;
}

type ViewMode = 'day' | 'week' | 'month';

// ── Constants ──

const HOUR_HEIGHT = 60;
const TOTAL_HOURS = 24;
const CONTENT_HEIGHT = TOTAL_HOURS * HOUR_HEIGHT;
const DAY_VIEWPORT_HEIGHT = 660;
const WEEK_VIEWPORT_HEIGHT = 660;
const WORK_START = 9;
const WORK_END = 17;
const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const DAY_NAMES_SHORT = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];
const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
];
const WEEKDAY_NAMES = ['Su', 'Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa'];

const TAG_COLORS: Record<number, string> = {
  1: '#e53935', 2: '#00897b', 3: '#1e88e5', 4: '#8e24aa',
  5: '#fdd835', 6: '#fb8c00', 7: '#e91e63', 8: '#00695c', 9: '#212121',
};

const STATUS_PRIORITY: Record<string, number> = {
  'TODO': 3, 'IN-PROGRESS': 2, 'DONE': 1,
};
const STATUS_COLORS: Record<string, string> = {
  'TODO': '#d32f2f', 'IN-PROGRESS': '#ed6c02', 'DONE': '#2e7d32',
};

// ── Helpers ──

function sameDay(a: Date, b: Date): boolean {
  return a.getFullYear() === b.getFullYear()
    && a.getMonth() === b.getMonth()
    && a.getDate() === b.getDate();
}

function dateKey(d: Date): string {
  return `${d.getFullYear()}-${d.getMonth()}-${d.getDate()}`;
}

function addDays(d: Date, n: number): Date {
  const r = new Date(d);
  r.setDate(r.getDate() + n);
  return r;
}

function getWeekStart(d: Date): Date {
  const r = new Date(d);
  r.setDate(r.getDate() - r.getDay());
  return r;
}

function hasTime(dateStr: string): boolean {
  if (!dateStr || dateStr.startsWith('0001-01-01')) return false;
  const d = new Date(dateStr);
  return d.getHours() !== 0 || d.getMinutes() !== 0;
}

function getMinutesFromMidnight(dateStr: string): number {
  if (!dateStr || dateStr.startsWith('0001-01-01')) return 0;
  const d = new Date(dateStr);
  return d.getHours() * 60 + d.getMinutes();
}

function formatTime(dateStr: string): string {
  if (!dateStr || dateStr.startsWith('0001-01-01')) return '';
  const d = new Date(dateStr);
  return `${d.getHours()}:${String(d.getMinutes()).padStart(2, '0')}`;
}

function formatHour(hour: number): string {
  const suffix = hour >= 12 ? 'PM' : 'AM';
  const h = hour > 12 ? hour - 12 : hour === 0 ? 12 : hour;
  return `${h} ${suffix}`;
}

function formatDateTitle(d: Date): string {
  return `${DAY_NAMES[d.getDay()]}, ${MONTH_NAMES[d.getMonth()]} ${d.getDate()}, ${d.getFullYear()}`;
}

function formatWeekTitle(d: Date): string {
  const start = getWeekStart(d);
  const end = addDays(start, 6);
  if (start.getMonth() === end.getMonth()) {
    return `${MONTH_NAMES[start.getMonth()]} ${start.getDate()} \u2013 ${end.getDate()}, ${start.getFullYear()}`;
  }
  if (start.getFullYear() === end.getFullYear()) {
    return `${MONTH_NAMES[start.getMonth()]} ${start.getDate()} \u2013 ${MONTH_NAMES[end.getMonth()]} ${end.getDate()}, ${end.getFullYear()}`;
  }
  return `${MONTH_NAMES[start.getMonth()]} ${start.getDate()}, ${start.getFullYear()} \u2013 ${MONTH_NAMES[end.getMonth()]} ${end.getDate()}, ${end.getFullYear()}`;
}

function formatMonthTitle(d: Date): string {
  return `${MONTH_NAMES[d.getMonth()]} ${d.getFullYear()}`;
}

function getEventColors(evt: AgendaEvent): { borderColor: string; bgColor: string } {
  let borderColor = '#57b986';
  let bgColor = 'var(--joy-palette-background-level1, #f0f0f0)';
  if (evt.Tags) {
    for (const tag of evt.Tags) {
      const n = Number(tag);
      if (!isNaN(n) && n > 0 && n < 10) {
        return { borderColor: TAG_COLORS[n], bgColor: `${TAG_COLORS[n]}18` };
      }
    }
  }
  return { borderColor, bgColor };
}

function getStatusColors(evt: AgendaEvent): { borderColor: string; bgColor: string } {
  const status = evt.Status || 'TODO';
  const borderColor = STATUS_COLORS[status] ?? STATUS_COLORS['TODO'];
  return { borderColor, bgColor: `${borderColor}18` };
}

function eventsForDay(allTodos: AgendaEvent[], day: Date): AgendaEvent[] {
  return allTodos.filter(evt => {
    if (!evt.Date?.Start || evt.Date.Start.startsWith('0001-01-01')) return false;
    return sameDay(new Date(evt.Date.Start), day);
  });
}

// ── Collision detection ──

function getCollisions(events: AgendaEvent[]): Map<number, { order: number; maxInSlot: number }> {
  const slots = 48;
  const slotOccupants: number[][] = Array.from({ length: slots }, () => []);
  events.forEach((evt, idx) => {
    const startMin = getMinutesFromMidnight(evt.Date.Start);
    let endMin = getMinutesFromMidnight(evt.Date.End);
    if (endMin <= startMin) endMin = startMin + 30;
    const startSlot = Math.floor(startMin / 30);
    const endSlot = Math.ceil(endMin / 30);
    for (let s = startSlot; s < Math.min(endSlot, slots); s++) {
      slotOccupants[s].push(idx);
    }
  });
  const result = new Map<number, { order: number; maxInSlot: number }>();
  events.forEach((_, idx) => result.set(idx, { order: 1, maxInSlot: 1 }));
  const assignedOrder = new Map<number, number>();
  for (const occupants of slotOccupants) {
    if (occupants.length <= 1) continue;
    occupants.forEach((evtIdx, i) => {
      const current = result.get(evtIdx)!;
      if (!assignedOrder.has(evtIdx)) assignedOrder.set(evtIdx, i + 1);
      const order = assignedOrder.get(evtIdx)!;
      result.set(evtIdx, { order, maxInSlot: Math.max(current.maxInSlot, occupants.length) });
    });
  }
  return result;
}

// ── Mini calendar helpers ──

function getMonthGrid(year: number, month: number): (Date | null)[][] {
  const first = new Date(year, month, 1);
  const startDow = first.getDay();
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const weeks: (Date | null)[][] = [];
  let week: (Date | null)[] = new Array(startDow).fill(null);
  for (let d = 1; d <= daysInMonth; d++) {
    week.push(new Date(year, month, d));
    if (week.length === 7) { weeks.push(week); week = []; }
  }
  if (week.length > 0) {
    while (week.length < 7) week.push(null);
    weeks.push(week);
  }
  return weeks;
}

function buildCalendarMarkers(todos: AgendaEvent[]): Map<string, string> {
  const dayMap = new Map<string, { priority: number; color: string }>();
  for (const todo of todos) {
    if (!todo.Date?.Start || todo.Date.Start.startsWith('0001-01-01')) continue;
    const d = new Date(todo.Date.Start);
    const key = dateKey(d);
    const status = todo.Status || 'TODO';
    const priority = STATUS_PRIORITY[status] ?? 1;
    const color = STATUS_COLORS[status] ?? STATUS_COLORS['TODO'];
    const existing = dayMap.get(key);
    if (!existing || priority > existing.priority) dayMap.set(key, { priority, color });
  }
  const result = new Map<string, string>();
  dayMap.forEach((v, k) => result.set(k, v.color));
  return result;
}

// ── Shared sub-components ──

function CurrentTimeMarker({ viewDate }: { viewDate: Date }) {
  const [now, setNow] = React.useState(new Date());
  React.useEffect(() => {
    const interval = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(interval);
  }, []);
  if (!sameDay(now, viewDate)) return null;
  const minutes = now.getHours() * 60 + now.getMinutes();
  const top = (minutes / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT;
  return (
    <Box sx={{ position: 'absolute', top: `${top}px`, left: 0, right: 0, height: '2px', borderTop: '2px dashed #e53935', zIndex: 10 }}>
      <Box sx={{ position: 'absolute', left: -4, top: -5, width: 8, height: 8, borderRadius: '50%', backgroundColor: '#e53935' }} />
    </Box>
  );
}

function WeekTimeMarker() {
  const [now, setNow] = React.useState(new Date());
  React.useEffect(() => {
    const interval = setInterval(() => setNow(new Date()), 60000);
    return () => clearInterval(interval);
  }, []);
  const minutes = now.getHours() * 60 + now.getMinutes();
  const top = (minutes / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT;
  return (
    <Box sx={{ position: 'absolute', top: `${top}px`, left: 0, right: 0, height: '2px', borderTop: '2px dashed #e53935', zIndex: 10, pointerEvents: 'none' }}>
      <Box sx={{ position: 'absolute', left: -4, top: -5, width: 8, height: 8, borderRadius: '50%', backgroundColor: '#e53935' }} />
    </Box>
  );
}

function MiniMonth({
  year, month, today, viewDate, markers, onSelectDate,
}: {
  year: number; month: number; today: Date; viewDate: Date;
  markers: Map<string, string>; onSelectDate: (d: Date) => void;
}) {
  const weeks = getMonthGrid(year, month);
  return (
    <Box sx={{ mb: 2 }}>
      <Typography level="body-sm" sx={{ fontWeight: 700, mb: 0.5, textAlign: 'center' }}>
        {MONTH_NAMES[month]} {year}
      </Typography>
      <Box component="table" sx={{ borderCollapse: 'collapse', width: '100%', tableLayout: 'fixed' }}>
        <thead>
          <tr>
            {WEEKDAY_NAMES.map((wd, i) => (
              <Box component="th" key={wd} sx={{ fontSize: '10px', fontWeight: 600, textAlign: 'center', pb: 0.25, color: (i === 0 || i === 6) ? 'warning.plainColor' : 'text.tertiary' }}>{wd}</Box>
            ))}
          </tr>
        </thead>
        <tbody>
          {weeks.map((week, wi) => (
            <tr key={wi}>
              {week.map((day, di) => {
                if (!day) return <td key={di} />;
                const isToday = sameDay(day, today);
                const isViewed = sameDay(day, viewDate);
                const isWeekend = di === 0 || di === 6;
                const marker = markers.get(dateKey(day));
                return (
                  <Box component="td" key={di} onClick={() => onSelectDate(day)}
                    sx={{ textAlign: 'center', fontSize: '11px', py: '2px', cursor: 'pointer', position: 'relative',
                      fontWeight: isToday ? 700 : 400, color: isWeekend ? 'warning.plainColor' : 'text.primary',
                      backgroundColor: isViewed ? 'primary.softBg' : isToday ? 'neutral.softBg' : 'transparent',
                      borderRadius: '4px', '&:hover': { backgroundColor: 'primary.softHoverBg' } }}>
                    {day.getDate()}
                    {marker && <Box sx={{ position: 'absolute', bottom: 0, left: '50%', transform: 'translateX(-50%)', width: 4, height: 4, borderRadius: '50%', backgroundColor: marker }} />}
                  </Box>
                );
              })}
            </tr>
          ))}
        </tbody>
      </Box>
    </Box>
  );
}

function UntimedSection({ events, onClickEvent }: { events: AgendaEvent[]; onClickEvent: (evt: AgendaEvent) => void }) {
  if (events.length === 0) return null;
  return (
    <Sheet variant="outlined" sx={{ width: '100%', borderRadius: 'sm', p: 1.5 }}>
      <Typography level="body-xs" sx={{ fontWeight: 700, color: 'text.tertiary', mb: 1 }}>All Day / No Time</Typography>
      <Box sx={{ display: 'flex', flexDirection: 'column', gap: 0.75 }}>
        {events.map((evt, idx) => {
          const { borderColor, bgColor } = getStatusColors(evt);
          return (
            <Box key={idx} onClick={() => onClickEvent(evt)}
              sx={{ borderLeft: `3px solid ${borderColor}`, backgroundColor: bgColor, borderRadius: '4px', px: 1, py: 0.5, cursor: 'pointer', '&:hover': { opacity: 0.85 } }}>
              <Typography level="body-xs" sx={{ fontWeight: 600, fontSize: evt.Headline.length > 40 ? '10px' : '12px', lineHeight: 1.2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {evt.Headline}
              </Typography>
            </Box>
          );
        })}
      </Box>
    </Sheet>
  );
}

// ── Time grid shared elements ──

function TimeColumn({ timeLabels }: { timeLabels: { hour: number; label: string }[] }) {
  return (
    <Box sx={{ width: 55, flexShrink: 0, borderRight: '1px solid', borderColor: 'divider', position: 'relative' }}>
      {timeLabels.map(({ hour, label }) => (
        <Typography key={hour} level="body-xs" sx={{
          position: 'absolute', top: `${hour * HOUR_HEIGHT}px`, right: 6, transform: 'translateY(-50%)',
          color: 'text.tertiary', fontSize: '10px', fontWeight: (hour >= WORK_START && hour < WORK_END) ? 600 : 400,
        }}>{label}</Typography>
      ))}
    </Box>
  );
}

function WorkingHoursOverlay() {
  return (
    <>
      <Box sx={{ position: 'absolute', top: `${WORK_START * HOUR_HEIGHT}px`, left: 0, right: 0, height: `${(WORK_END - WORK_START) * HOUR_HEIGHT}px`, backgroundColor: 'background.surface', zIndex: 0 }} />
      <Box sx={{ position: 'absolute', top: 0, left: 0, right: 0, height: `${WORK_START * HOUR_HEIGHT}px`, backgroundColor: 'background.level1', opacity: 0.3, zIndex: 0 }} />
      <Box sx={{ position: 'absolute', top: `${WORK_END * HOUR_HEIGHT}px`, left: 0, right: 0, height: `${(TOTAL_HOURS - WORK_END) * HOUR_HEIGHT}px`, backgroundColor: 'background.level1', opacity: 0.3, zIndex: 0 }} />
    </>
  );
}

function HourGridLines({ timeLabels }: { timeLabels: { hour: number; label: string }[] }) {
  return (
    <>
      {timeLabels.map(({ hour }) => (
        <Box key={hour} sx={{ position: 'absolute', top: `${hour * HOUR_HEIGHT}px`, left: 0, right: 0, height: '1px', backgroundColor: 'divider', opacity: (hour >= WORK_START && hour < WORK_END) ? 0.6 : 0.4, zIndex: 1 }} />
      ))}
    </>
  );
}

// ── Day View ──

function DayView({ events, viewDate, onClickEvent }: {
  events: AgendaEvent[]; viewDate: Date; onClickEvent: (evt: AgendaEvent) => void;
}) {
  const scrollRef = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = WORK_START * HOUR_HEIGHT;
  }, []);

  const timed = events.filter(evt => hasTime(evt.Date?.Start));
  const untimed = events.filter(evt => !hasTime(evt.Date?.Start));
  const collisions = getCollisions(timed);

  const timeLabels: { hour: number; label: string }[] = [];
  for (let h = 0; h < TOTAL_HOURS; h++) timeLabels.push({ hour: h, label: formatHour(h) });

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5, flex: 1, minWidth: 0, maxWidth: 720 }}>
      <Sheet ref={scrollRef} variant="outlined" sx={{ width: '100%', height: DAY_VIEWPORT_HEIGHT, borderRadius: 'sm', overflowY: 'auto', overflowX: 'hidden' }}>
        <Box sx={{ display: 'flex', height: CONTENT_HEIGHT, position: 'relative' }}>
          <TimeColumn timeLabels={timeLabels} />
          <Box sx={{ flex: 1, position: 'relative' }}>
            <WorkingHoursOverlay />
            <HourGridLines timeLabels={timeLabels} />
            <CurrentTimeMarker viewDate={viewDate} />
            {timed.map((evt, idx) => {
              const startMin = getMinutesFromMidnight(evt.Date.Start);
              let endMin = getMinutesFromMidnight(evt.Date.End);
              if (endMin <= startMin) endMin = startMin + 30;
              const top = (startMin / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT;
              const height = Math.max(((endMin - startMin) / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT, 20);
              const collision = collisions.get(idx)!;
              const widthPercent = 100 / collision.maxInSlot;
              const leftPercent = widthPercent * (collision.order - 1);
              const { borderColor, bgColor } = getEventColors(evt);
              const timeStr = `${formatTime(evt.Date.Start)} - ${formatTime(evt.Date.End)}`;
              return (
                <Box key={idx} onClick={() => onClickEvent(evt)} sx={{
                  position: 'absolute', top: `${top}px`, left: `${leftPercent}%`, width: `${widthPercent}%`, height: `${height}px`,
                  borderLeft: `3px solid ${borderColor}`, backgroundColor: bgColor, borderRadius: '4px', px: 1, py: 0.5,
                  overflow: 'hidden', cursor: 'pointer', boxSizing: 'border-box', zIndex: 2, '&:hover': { opacity: 0.85 },
                }}>
                  <Typography level="body-xs" sx={{ fontWeight: 600, fontSize: evt.Headline.length > 40 ? '10px' : '12px', lineHeight: 1.2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {evt.Headline}
                  </Typography>
                  <Typography level="body-xs" sx={{ fontSize: '10px', color: 'text.tertiary' }}>{timeStr}</Typography>
                </Box>
              );
            })}
          </Box>
        </Box>
      </Sheet>
      <UntimedSection events={untimed} onClickEvent={onClickEvent} />
    </Box>
  );
}

// ── Week View ──

function WeekView({ allTodos, viewDate, today, onClickEvent }: {
  allTodos: AgendaEvent[]; viewDate: Date; today: Date; onClickEvent: (evt: AgendaEvent) => void;
}) {
  const scrollRef = React.useRef<HTMLDivElement>(null);
  React.useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = WORK_START * HOUR_HEIGHT;
  }, []);

  const weekStart = getWeekStart(viewDate);
  const days = Array.from({ length: 7 }, (_, i) => addDays(weekStart, i));

  const timeLabels: { hour: number; label: string }[] = [];
  for (let h = 0; h < TOTAL_HOURS; h++) timeLabels.push({ hour: h, label: formatHour(h) });

  // Gather untimed events across the week
  const weekUntimed: AgendaEvent[] = [];
  days.forEach(day => {
    eventsForDay(allTodos, day).filter(e => !hasTime(e.Date?.Start)).forEach(e => weekUntimed.push(e));
  });

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', gap: 1.5, flex: 1, minWidth: 0 }}>
      <Sheet ref={scrollRef} variant="outlined" sx={{ width: '100%', height: WEEK_VIEWPORT_HEIGHT, borderRadius: 'sm', overflowY: 'auto', overflowX: 'hidden' }}>
        {/* Day headers */}
        <Box sx={{ display: 'flex', position: 'sticky', top: 0, zIndex: 20, backgroundColor: 'background.surface', borderBottom: '1px solid', borderColor: 'divider' }}>
          <Box sx={{ width: 55, flexShrink: 0, borderRight: '1px solid', borderColor: 'divider' }} />
          {days.map((day, di) => {
            const isToday = sameDay(day, today);
            const isWeekend = di === 0 || di === 6;
            return (
              <Box key={di} sx={{
                flex: 1, textAlign: 'center', py: 0.75, borderRight: di < 6 ? '1px solid' : 'none', borderColor: 'divider',
                backgroundColor: isToday ? 'primary.softBg' : 'transparent',
              }}>
                <Typography level="body-xs" sx={{ fontWeight: 600, color: isWeekend ? 'warning.plainColor' : 'text.primary', fontSize: '11px' }}>
                  {DAY_NAMES_SHORT[di]}
                </Typography>
                <Typography level="body-xs" sx={{ fontWeight: isToday ? 700 : 400, color: isWeekend ? 'warning.plainColor' : 'text.primary', fontSize: '13px' }}>
                  {day.getDate()}
                </Typography>
              </Box>
            );
          })}
        </Box>
        {/* Time grid */}
        <Box sx={{ display: 'flex', height: CONTENT_HEIGHT, position: 'relative' }}>
          <TimeColumn timeLabels={timeLabels} />
          {days.map((day, di) => {
            const dayEvents = eventsForDay(allTodos, day).filter(e => hasTime(e.Date?.Start));
            const collisions = getCollisions(dayEvents);
            const isToday = sameDay(day, today);
            return (
              <Box key={di} sx={{ flex: 1, position: 'relative', borderRight: di < 6 ? '1px solid' : 'none', borderColor: 'divider' }}>
                <WorkingHoursOverlay />
                <HourGridLines timeLabels={timeLabels} />
                {isToday && <WeekTimeMarker />}
                {dayEvents.map((evt, idx) => {
                  const startMin = getMinutesFromMidnight(evt.Date.Start);
                  let endMin = getMinutesFromMidnight(evt.Date.End);
                  if (endMin <= startMin) endMin = startMin + 30;
                  const top = (startMin / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT;
                  const height = Math.max(((endMin - startMin) / (TOTAL_HOURS * 60)) * CONTENT_HEIGHT, 20);
                  const collision = collisions.get(idx)!;
                  const widthPercent = 100 / collision.maxInSlot;
                  const leftPercent = widthPercent * (collision.order - 1);
                  const { borderColor, bgColor } = getEventColors(evt);
                  return (
                    <Box key={idx} onClick={() => onClickEvent(evt)} sx={{
                      position: 'absolute', top: `${top}px`, left: `${leftPercent}%`, width: `${widthPercent}%`, height: `${height}px`,
                      borderLeft: `3px solid ${borderColor}`, backgroundColor: bgColor, borderRadius: '3px', px: 0.5, py: '2px',
                      overflow: 'hidden', cursor: 'pointer', boxSizing: 'border-box', zIndex: 2, '&:hover': { opacity: 0.85 },
                    }}>
                      <Typography level="body-xs" sx={{ fontWeight: 600, fontSize: '10px', lineHeight: 1.2, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                        {evt.Headline}
                      </Typography>
                    </Box>
                  );
                })}
              </Box>
            );
          })}
        </Box>
      </Sheet>
      <UntimedSection events={weekUntimed} onClickEvent={onClickEvent} />
    </Box>
  );
}

// ── Month View ──

function MonthView({ allTodos, viewDate, today, onClickEvent, onSelectDate }: {
  allTodos: AgendaEvent[]; viewDate: Date; today: Date;
  onClickEvent: (evt: AgendaEvent) => void; onSelectDate: (d: Date) => void;
}) {
  const weeks = getMonthGrid(viewDate.getFullYear(), viewDate.getMonth());
  const MAX_VISIBLE = 3;

  return (
    <Sheet variant="outlined" sx={{ flex: 1, minWidth: 0, borderRadius: 'sm', overflow: 'hidden' }}>
      {/* Header row */}
      <Box sx={{ display: 'flex', borderBottom: '1px solid', borderColor: 'divider' }}>
        {WEEKDAY_NAMES.map((wd, i) => (
          <Box key={wd} sx={{
            flex: 1, textAlign: 'center', py: 0.75,
            borderRight: i < 6 ? '1px solid' : 'none', borderColor: 'divider',
          }}>
            <Typography level="body-xs" sx={{ fontWeight: 600, fontSize: '11px', color: (i === 0 || i === 6) ? 'warning.plainColor' : 'text.tertiary' }}>
              {wd}
            </Typography>
          </Box>
        ))}
      </Box>
      {/* Week rows */}
      {weeks.map((week, wi) => (
        <Box key={wi} sx={{ display: 'flex', minHeight: 100, borderBottom: wi < weeks.length - 1 ? '1px solid' : 'none', borderColor: 'divider' }}>
          {week.map((day, di) => {
            if (!day) {
              return <Box key={di} sx={{ flex: 1, borderRight: di < 6 ? '1px solid' : 'none', borderColor: 'divider', backgroundColor: 'background.level1', opacity: 0.4 }} />;
            }
            const isToday = sameDay(day, today);
            const isWeekend = di === 0 || di === 6;
            const dayEvts = eventsForDay(allTodos, day);
            const visible = dayEvts.slice(0, MAX_VISIBLE);
            const overflow = dayEvts.length - MAX_VISIBLE;
            return (
              <Box key={di} sx={{
                flex: 1, p: 0.5, borderRight: di < 6 ? '1px solid' : 'none', borderColor: 'divider',
                backgroundColor: isToday ? 'primary.softBg' : isWeekend ? 'background.level1' : 'transparent',
                cursor: 'pointer', '&:hover': { backgroundColor: 'primary.softHoverBg' },
                display: 'flex', flexDirection: 'column',
              }} onClick={() => onSelectDate(day)}>
                <Typography level="body-xs" sx={{
                  fontWeight: isToday ? 700 : 400, fontSize: '12px', mb: 0.5,
                  color: isWeekend ? 'warning.plainColor' : 'text.primary',
                }}>
                  {day.getDate()}
                </Typography>
                <Box sx={{ display: 'flex', flexDirection: 'column', gap: '2px', flex: 1, minWidth: 0 }}>
                  {visible.map((evt, idx) => {
                    const { borderColor, bgColor } = hasTime(evt.Date?.Start) ? getEventColors(evt) : getStatusColors(evt);
                    return (
                      <Box key={idx} onClick={(e) => { e.stopPropagation(); onClickEvent(evt); }}
                        sx={{ borderLeft: `2px solid ${borderColor}`, backgroundColor: bgColor, borderRadius: '2px', px: 0.5, cursor: 'pointer', '&:hover': { opacity: 0.85 } }}>
                        <Typography level="body-xs" sx={{ fontSize: '10px', lineHeight: 1.3, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                          {hasTime(evt.Date?.Start) && <Box component="span" sx={{ color: 'text.tertiary', mr: 0.5 }}>{formatTime(evt.Date.Start)}</Box>}
                          {evt.Headline}
                        </Typography>
                      </Box>
                    );
                  })}
                  {overflow > 0 && (
                    <Typography level="body-xs" sx={{ fontSize: '9px', color: 'text.tertiary', pl: 0.5 }}>
                      +{overflow} more
                    </Typography>
                  )}
                </Box>
              </Box>
            );
          })}
        </Box>
      ))}
    </Sheet>
  );
}

// ── Main component ──

export default function Agenda() {
  const today = React.useMemo(() => new Date(), []);
  const [viewDate, setViewDate] = React.useState(new Date());
  const [viewMode, setViewMode] = React.useState<ViewMode>('day');
  const [dayEvents, setDayEvents] = React.useState<AgendaEvent[]>([]);
  const [allTodos, setAllTodos] = React.useState<AgendaEvent[]>([]);
  const [calendarMarkers, setCalendarMarkers] = React.useState<Map<string, string>>(new Map());

  const [modalOpen, setModalOpen] = React.useState(false);
  const [modalEvent, setModalEvent] = React.useState<AgendaEvent | null>(null);
  const [modalContent, setModalContent] = React.useState<{ headline: string; html: string; status: string; tags: string[]; date: string } | null>(null);

  // Navigation steps by view mode
  const goNext = React.useCallback(() => {
    setViewDate(d => {
      if (viewMode === 'day') return addDays(d, 1);
      if (viewMode === 'week') return addDays(d, 7);
      return new Date(d.getFullYear(), d.getMonth() + 1, 1);
    });
  }, [viewMode]);
  const goPrev = React.useCallback(() => {
    setViewDate(d => {
      if (viewMode === 'day') return addDays(d, -1);
      if (viewMode === 'week') return addDays(d, -7);
      return new Date(d.getFullYear(), d.getMonth() - 1, 1);
    });
  }, [viewMode]);
  const goToday = React.useCallback(() => setViewDate(new Date()), []);

  const fetchModalContent = React.useCallback(async (evt: AgendaEvent) => {
    const dateStr = evt.Date?.Start && !evt.Date.Start.startsWith('0001-01-01') ? evt.Date.Start : '';
    try {
      const data = await ODb.todoHtml(evt.Hash);
      setModalContent({ headline: data.Headline || evt.Headline, html: data.Content || '<p>No content</p>', status: evt.Status || '', tags: evt.Tags || [], date: dateStr });
    } catch (e) {
      setModalContent({ headline: evt.Headline, html: '<p>Failed to load content</p>', status: evt.Status || '', tags: evt.Tags || [], date: dateStr });
    }
  }, []);

  const openEntry = React.useCallback(async (evt: AgendaEvent) => {
    const dateStr = evt.Date?.Start && !evt.Date.Start.startsWith('0001-01-01') ? evt.Date.Start : '';
    setModalEvent(evt);
    setModalOpen(true);
    setModalContent({ headline: evt.Headline, html: '<p>Loading...</p>', status: evt.Status || '', tags: evt.Tags || [], date: dateStr });
    fetchModalContent(evt);
  }, [fetchModalContent]);

  // Re-fetch modal content while open to pick up disk changes
  React.useEffect(() => {
    if (!modalOpen || !modalEvent) return;
    const interval = setInterval(() => fetchModalContent(modalEvent), 5000);
    return () => clearInterval(interval);
  }, [modalOpen, modalEvent, fetchModalContent]);

  // Keyboard navigation
  React.useEffect(() => {
    const handler = (e: KeyboardEvent) => {
      if (modalOpen) return;
      if (e.target instanceof HTMLInputElement || e.target instanceof HTMLTextAreaElement) return;
      if (e.key === 'ArrowRight' || e.key === 'f') goNext();
      else if (e.key === 'ArrowLeft' || e.key === 'b') goPrev();
      else if (e.key === 't' || e.key === '.') goToday();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [goNext, goPrev, goToday, modalOpen]);

  // Fetch day events for day view
  React.useEffect(() => {
    if (viewMode !== 'day') return;
    let cancelled = false;
    (async () => {
      try {
        const data = await ODb.agendaRest<AgendaEvent[]>(viewDate);
        if (!cancelled && Array.isArray(data)) setDayEvents(data);
      } catch (e) { console.error('Failed to fetch agenda:', e); }
    })();
    const interval = setInterval(async () => {
      try {
        const data = await ODb.agendaRest<AgendaEvent[]>(viewDate);
        if (!cancelled && Array.isArray(data)) setDayEvents(data);
      } catch (e) {}
    }, 30000);
    return () => { cancelled = true; clearInterval(interval); };
  }, [viewDate, viewMode]);

  // Fetch all active TODOs for week/month views and calendar markers
  React.useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const todos = await ODb.activeTodos<AgendaEvent[]>();
        if (!cancelled && Array.isArray(todos)) {
          setAllTodos(todos);
          setCalendarMarkers(buildCalendarMarkers(todos));
        }
      } catch (e) { console.error('Failed to fetch todos:', e); }
    })();
    return () => { cancelled = true; };
  }, []);

  // Title based on view mode
  const title = viewMode === 'day' ? formatDateTitle(viewDate)
    : viewMode === 'week' ? formatWeekTitle(viewDate)
    : formatMonthTitle(viewDate);

  const navLabel = viewMode === 'day' ? 'day' : viewMode === 'week' ? 'week' : 'month';

  // Calendar sidebar months
  const calendarMonths = React.useMemo(() => {
    const vd = viewDate;
    return [
      { year: new Date(vd.getFullYear(), vd.getMonth() - 1, 1).getFullYear(), month: new Date(vd.getFullYear(), vd.getMonth() - 1, 1).getMonth() },
      { year: vd.getFullYear(), month: vd.getMonth() },
      { year: new Date(vd.getFullYear(), vd.getMonth() + 1, 1).getFullYear(), month: new Date(vd.getFullYear(), vd.getMonth() + 1, 1).getMonth() },
    ];
  }, [viewDate]);

  // When clicking a day in month view, switch to day view
  const handleMonthDayClick = React.useCallback((d: Date) => {
    setViewDate(d);
    setViewMode('day');
  }, []);

  return (
    <Box sx={{ width: '100%' }}>
      {/* Toolbar: tabs + nav */}
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 1.5, gap: 1, flexWrap: 'wrap' }}>
        <Tabs value={viewMode} onChange={(_, v) => setViewMode(v as ViewMode)} size="sm" sx={{ borderRadius: 'sm' }}>
          <TabList variant="outlined">
            <Tab value="day">Day</Tab>
            <Tab value="week">Week</Tab>
            <Tab value="month">Month</Tab>
          </TabList>
        </Tabs>
        <IconButton size="sm" variant="outlined" onClick={goPrev} title={`Previous ${navLabel}`}>
          <KeyboardArrowLeftIcon />
        </IconButton>
        <IconButton size="sm" variant="outlined" onClick={goToday} title="Today (t / .)">
          <TodayIcon />
        </IconButton>
        <IconButton size="sm" variant="outlined" onClick={goNext} title={`Next ${navLabel}`}>
          <KeyboardArrowRightIcon />
        </IconButton>
        <Typography level="title-lg" sx={{ ml: 1 }}>
          {title}
        </Typography>
        {sameDay(viewDate, today) && viewMode === 'day' && (
          <Typography level="body-xs" sx={{ color: 'primary.plainColor', fontWeight: 600 }}>Today</Typography>
        )}
      </Box>

      {/* Main content + calendar sidebar */}
      <Box sx={{ display: 'flex', gap: 2 }}>
        {/* View area */}
        {viewMode === 'day' && <DayView events={dayEvents} viewDate={viewDate} onClickEvent={openEntry} />}
        {viewMode === 'week' && <WeekView allTodos={allTodos} viewDate={viewDate} today={today} onClickEvent={openEntry} />}
        {viewMode === 'month' && <MonthView allTodos={allTodos} viewDate={viewDate} today={today} onClickEvent={openEntry} onSelectDate={handleMonthDayClick} />}

        {/* Mini calendar sidebar */}
        <Sheet variant="outlined" sx={{ width: 200, flexShrink: 0, borderRadius: 'sm', p: 1.5, alignSelf: 'stretch', display: { xs: 'none', md: 'block' } }}>
          {calendarMonths.map(({ year, month }) => (
            <MiniMonth key={`${year}-${month}`} year={year} month={month} today={today} viewDate={viewDate} markers={calendarMarkers} onSelectDate={setViewDate} />
          ))}
          <Box sx={{ mt: 1, display: 'flex', flexDirection: 'column', gap: 0.5 }}>
            <Typography level="body-xs" sx={{ fontWeight: 600, color: 'text.tertiary' }}>Legend</Typography>
            {Object.entries(STATUS_COLORS).map(([status, color]) => (
              <Box key={status} sx={{ display: 'flex', alignItems: 'center', gap: 0.75 }}>
                <Box sx={{ width: 8, height: 8, borderRadius: '50%', backgroundColor: color, flexShrink: 0 }} />
                <Typography level="body-xs">{status}</Typography>
              </Box>
            ))}
          </Box>
        </Sheet>
      </Box>

      {/* Entry detail modal */}
      <Modal open={modalOpen} onClose={() => setModalOpen(false)}>
        <ModalDialog sx={{ maxWidth: 600, width: '90vw', maxHeight: '80vh', overflow: 'auto' }}>
          <ModalClose />
          {modalContent && (
            <Box sx={{ pt: 1 }}>
              <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 2 }}>
                <Typography level="title-lg" sx={{ mb: 0.5 }}>{modalContent.headline}</Typography>
                {modalContent.date && (
                  <Typography level="body-xs" sx={{
                    color: 'text.tertiary', whiteSpace: 'nowrap', flexShrink: 0,
                    fontFamily: 'monospace', fontSize: '11px', mt: 0.5,
                  }}>
                    {(() => {
                      const d = new Date(modalContent.date);
                      return `${DAY_NAMES[d.getDay()]}, ${MONTH_NAMES[d.getMonth()]} ${d.getDate()}` +
                        (hasTime(modalContent.date) ? ` \u00b7 ${formatTime(modalContent.date)}` : '');
                    })()}
                  </Typography>
                )}
              </Box>
              <Box sx={{ display: 'flex', gap: 0.75, mb: 1.5, flexWrap: 'wrap' }}>
                {modalContent.status && (
                  <Chip size="sm" variant="soft" color={modalContent.status === 'DONE' ? 'success' : modalContent.status === 'IN-PROGRESS' ? 'warning' : 'danger'}>
                    {modalContent.status}
                  </Chip>
                )}
                {modalContent.tags.map(tag => <Chip key={tag} size="sm" variant="outlined">{tag}</Chip>)}
              </Box>
              <Box sx={{
                '& h1, & h2, & h3, & h4': { mt: 1.5, mb: 0.5 }, '& p': { my: 0.5 }, '& ul, & ol': { pl: 2.5 },
                '& pre': { backgroundColor: 'background.level1', p: 1, borderRadius: 'sm', overflow: 'auto', fontSize: '12px' },
                '& code': { fontSize: '12px' }, '& a': { color: 'primary.plainColor' }, fontSize: '14px', lineHeight: 1.6,
              }} dangerouslySetInnerHTML={{ __html: modalContent.html }} />
            </Box>
          )}
        </ModalDialog>
      </Modal>
    </Box>
  );
}
