function OrgHeadline({row, isEditing, onCommit, onCancel, onStartEdit}: {row: any, isEditing: boolean, onCommit: (value: string) => void, onCancel: () => void, onStartEdit: (row: any) => void}) {
  const inputRef = React.useRef<HTMLInputElement>(null);
  const blurTimeoutRef = React.useRef<ReturnType<typeof setTimeout> | null>(null);
  const committedRef = React.useRef(false);
  const [localValue, setLocalValue] = React.useState(row.Headline);

  React.useEffect(() => {
    if (isEditing) {
      setLocalValue(row.Headline);
      committedRef.current = false;
      const t = setTimeout(() => {
        if (inputRef.current) {
          inputRef.current.focus();
          inputRef.current.select();
        }
      }, 50);
      return () => clearTimeout(t);
    }
  }, [isEditing]);

  React.useEffect(() => {
    return () => {
      if (blurTimeoutRef.current) clearTimeout(blurTimeoutRef.current);
    };
  }, []);

  const handleBlur = () => {
    blurTimeoutRef.current = setTimeout(() => {
      if (!committedRef.current) {
        committedRef.current = true;
        onCancel();
      }
    }, 150);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      if (!committedRef.current) {
        committedRef.current = true;
        if (blurTimeoutRef.current) clearTimeout(blurTimeoutRef.current);
        onCommit(localValue);
      }
    }
    if (e.key === 'Escape') {
      e.preventDefault();
      if (!committedRef.current) {
        committedRef.current = true;
        if (blurTimeoutRef.current) clearTimeout(blurTimeoutRef.current);
        onCancel();
      }
    }
  };

  return (
    <td>
      <Box
        sx={{ display: 'flex', gap: 2, alignItems: 'center' }}
        onContextMenu={(e) => { e.preventDefault(); onStartEdit(row); }}
      >
        {isEditing ? (
          <input
            ref={inputRef}
            value={localValue}
            onChange={(e) => setLocalValue(e.target.value)}
            onKeyDown={handleKeyDown}
            onBlur={handleBlur}
            style={{ fontSize: '0.75rem', fontFamily: 'inherit', width: '100%', padding: '2px 4px', border: '1px solid var(--joy-palette-primary-outlinedBorder)', borderRadius: 4, outline: 'none' }}
          />
        ) : (
          <Typography level="body-xs">{row.Headline}</Typography>
        )}
      </Box>
    </td>
  );
}

